class Solution:
    def letterCombinations(self, digits: str) -> list[str]:
        if not digits:
            return []

        keypad_map = {
            '2': "abc",
            '3': "def",
            '4': "ghi",
            '5': "jkl",
            '6': "mno",
            '7': "pqrs",
            '8': "tuv",
            '9': "wxyz"
        }

        result = []

        def backtrack(index, current_combination):
            if index == len(digits):
                result.append("".join(current_combination))
                return

            digit = digits[index]
            if digit in keypad_map:
                letters = keypad_map[digit]
                for letter in letters:
                    current_combination.append(letter)
                    backtrack(index + 1, current_combination)
                    current_combination.pop()
            else:
                # Handle digits not in keypad_map (e.g., '0', '1') by skipping them
                # and proceeding to the next digit without adding characters.
                backtrack(index + 1, current_combination)

        backtrack(0, [])
        return result
